class Solution:
    def maxProfit(self, prices: list[list[int]]) -> int:
        n = len(prices)
        maxProfit = 0
        for i in range(n):
            maxPrice = 0
            for j in range(len(prices[0])):
                maxPrice = max(maxPrice, prices[i][j])
            maxProfit += maxPrice
        return maxProfit

class Main:
    def readInput(self):
        return [int(x) for x in input().split(\n) if x]

    def main(self):
        t = 1
        for i in range(t):
            n = self.readInput()[0]
            prices = [list(map(int, input().split())) for _ in range(n)]
            solution = Solution()
            print(solution.maxProfit(prices))

