class Solution {
public:
    int maxProfit(vector<vector<int>>& prices) {
        int n = prices.size();
        int maxProfit = 0;
        for (int i = 0; i < n; i++) {
            int maxPrice = 0;
            for (int j = 0; j < prices[0].size(); j++) {
                maxPrice = std::max(maxPrice, prices[i][j]);
            }
            maxProfit += maxPrice;
        }
        return maxProfit;
    }
};
class Main {
public:
    int main() {
        std::cin >> n;
        vector<vector<int>> prices(n, vector<int>(n));
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                std::cin >> prices[i][j];
            }
        }
        Solution solution;
        std::cout << solution.maxProfit(prices) << std::endl;
        return 0;
    }
};
